diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
index fdef49e310f8..4815d7f8cbe6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -850,6 +850,23 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
       }
     }

+    {
+      // trunc (lshr/ashr C, X) to i1 --> icmp eq/ult X, log2(C')
+      const APInt *ShC;
+      if (match(Src, m_Shr(m_APInt(ShC), m_Value(X)))) {
+        if (ShC->isPowerOf2()) {
+          // trunc (shr Pow2, X) to i1 --> icmp eq X, log2(Pow2)
+          return new ICmpInst(ICmpInst::ICMP_EQ, X,
+                              ConstantInt::get(SrcTy, ShC->logBase2()));
+        }
+        if ((*ShC + 1).isPowerOf2()) {
+          // trunc (shr (Pow2 - 1), X) to i1 --> icmp ult X, log2(Pow2)
+          return new ICmpInst(ICmpInst::ICMP_ULT, X,
+                              ConstantInt::get(SrcTy, (*ShC + 1).logBase2()));
+        }
+      }
+    }
+
     if (Trunc.hasNoUnsignedWrap() || Trunc.hasNoSignedWrap()) {
       Value *X, *Y;
       if (match(Src, m_Xor(m_Value(X), m_Value(Y))))

